define('taoMediaManager/qtiCreator/widgets/static/table/Widget',['jquery', 'taoQtiItem/qtiCreator/widgets/static/Widget', 'taoMediaManager/qtiCreator/widgets/static/table/states/states', 'taoQtiItem/qtiCreator/widgets/static/helpers/widget', 'tpl!taoQtiItem/qtiCreator/tpl/toolbars/table'], function ($, Widget, states, helper, toolbarTpl) {
  'use strict';

  var TableWidget = Widget.clone();
  TableWidget.initCreator = function () {
    this.registerStates(states);
    Widget.initCreator.call(this);
  };
  TableWidget.buildContainer = function () {
    var table = this.element;
    helper.buildBlockContainer(this);
    if (table.attr('class')) {
      this.$container.addClass(table.attr('class'));
    }
    return this;
  };
  TableWidget.createToolbar = function () {
    var self = this,
      $tlb = $(toolbarTpl({
        serial: this.serial,
        state: 'active'
      }));
    this.$container.append($tlb);
    $tlb.find('[data-role="delete"]').on('click.widget-box', function (e) {
      e.stopPropagation();
      self.changeState('deleting');
    });
    return this;
  };
  return TableWidget;
});
