define('taoMediaManager/qtiCreator/renderers/Img',['lodash', 'context', 'taoQtiItem/qtiCommonRenderer/renderers/Img', 'taoMediaManager/qtiCreator/widgets/static/img/Widget', 'taoQtiItem/qtiCreator/widgets/static/figure/Widget', 'taoQtiItem/qtiCreator/model/Figure', 'taoQtiItem/qtiCreator/helper/findParentElement'], function (_, context, Renderer, Widget, FigureWidget, FigureModel, findParentElement) {
  'use strict';

  var CreatorImg = _.clone(Renderer);
  var DISABLE_FIGURE_WIDGET = context.featureFlags['FEATURE_FLAG_DISABLE_FIGURE_WIDGET'];
  CreatorImg.render = function render(img, options) {
    var $container = Renderer.getContainer(img);
    if ($container.parent('figure').length || !DISABLE_FIGURE_WIDGET && $container.parent('span').length && $container.parent('span').data('figure')) {
      if (!DISABLE_FIGURE_WIDGET && !$container.parent('figure').length && $container.siblings('figcaption').length) {
        $container.siblings('figcaption').remove();
      }
      return CreatorImg;
    }
    options = options || {};
    options.baseUrl = this.getOption('baseUrl');
    options.uri = this.getOption('uri');
    options.lang = this.getOption('lang');
    options.mediaManager = this.getOption('mediaManager');
    options.assetManager = this.getAssetManager();
    if (!DISABLE_FIGURE_WIDGET && !$container.closest('.qti-choice, .qti-flow-container').length && !$container.closest('.qti-table caption').length) {
      var parent = findParentElement(img.rootElement, img.serial);
      parent.removeElement(img);
      var figure = new FigureModel();
      parent.setElement(figure);
      var figureRenderer = parent.getRenderer();
      if (figureRenderer) {
        figure.setRenderer(figureRenderer);
        figureRenderer.load(() => {}, ['figure']);
      }
      figure.setElement(img);
      var $wrap = $container.wrap("<span data-serial=\"".concat(figure.serial, "\">")).parent();
      FigureWidget.build(figure, $wrap, this.getOption('bodyElementOptionForm'), options);
    } else {
      Widget.build(img, Renderer.getContainer(img), this.getOption('bodyElementOptionForm'), options);
    }
  };
  return CreatorImg;
});
