define('taoMediaManager/controller/contextType',['lodash'], function (_) {
  'use strict';

  return function getContextType(actionContext) {
    if (_.isArray(actionContext.context)) {
      return actionContext.context[0];
    }
    return actionContext.type || actionContext.context || (actionContext.uri ? 'instance' : 'class');
  };
});
