define('taoMediaManager/qtiCreator/plugins/menu/save',['jquery', 'i18n', 'core/plugin', 'ui/hider', 'tpl!taoQtiItem/qtiCreator/plugins/button'], function ($, __, pluginFactory, hider, buttonTpl) {
  'use strict';
  return pluginFactory({
    name: 'save',
    init() {
      var sharedStimulusCreator = this.getHost();
      this.$element = $(buttonTpl({
        icon: 'save',
        title: __('Save the asset'),
        text: __('Save'),
        cssClass: 'save-trigger',
        testId: 'save-the-asset'
      })).on('click', e => {
        e.preventDefault();
        this.disable();
        $('#item-editor-panel').trigger('beforesave.qti-creator');
        sharedStimulusCreator.trigger('save');
      });
      this.hide();
      this.disable();
      sharedStimulusCreator.on('ready saved error', () => {
        this.enable();
      });
    },
    render() {
      var $container = this.getAreaBroker().getMenuArea();
      $container.append(this.$element);
      this.show();
    },
    destroy() {
      this.$element.remove();
    },
    enable() {
      this.$element.removeProp('disabled').removeClass('disabled');
    },
    disable() {
      this.$element.prop('disabled', true).addClass('disabled');
    },
    show() {
      hider.show(this.$element);
    },
    hide() {
      hider.hide(this.$element);
    }
  });
});
