define('taoMediaManager/controller/editInstance',['jquery', 'lodash', 'layout/actions/binder', 'ui/previewer', 'util/url', 'taoMediaManager/previewer/component/qtiSharedStimulusItem', 'core/logger', 'ui/feedback', 'layout/loading-bar'], function ($, _, binder, previewer, urlUtil, qtiItemPreviewerFactory, loggerFactory, feedback, loadingBar) {
  'use strict';

  var logger = loggerFactory('taoMediaManager/editInstance');
  var manageMediaController = {
    start() {
      var $previewer = $('.previewer');
      var file = {};
      file.url = $previewer.data('url');
      file.mime = $previewer.data('type');
      var isPreviewEnabled = $previewer.data('enabled');
      var isPassage = file.mime === 'application/qti+xml';
      if (isPreviewEnabled) {
        if (!isPassage) {
          file.containerClass = 'no-background';
          $previewer.previewer(file);
        } else {
          loadingBar.start();
          qtiItemPreviewerFactory($previewer, {
            itemUri: $('#edit-media').data('uri')
          }).on('error', function (err) {
            if (!_.isUndefined(err.message)) {
              feedback().error(err.message);
            }
            logger.error(err);
          }).on('preview-loaded', loadingBar.stop);
        }
      }
      if (isPassage) {
        $('#media-authoring').show();
      } else {
        $('#media-authoring').hide();
      }
      $('#edit-media').off().on('click', function () {
        var action = {
          binding: 'load',
          url: urlUtil.route('editMedia', 'MediaImport', 'taoMediaManager')
        };
        binder.exec(action, {
          classUri: this.dataset.classuri,
          id: this.dataset.uri
        } || this._resourceContext);
      });
    }
  };
  return manageMediaController;
});
